// Reconstruct conversation history from Redis
const redisData = $input.first().json;
const body = $('Webhook – Agent Chat').item.json.body;
const userMessage = body.message;
const sessionId = body.session_id;
const userId = body.user_id || 'anonymous';

// Parse stored memory or start fresh
let history = [];
try {
  history = JSON.parse(redisData.value || '[]');
} catch (e) {
  history = [];
}

// Keep last 10 turns (20 messages) to stay within context window
if (history.length > 20) history = history.slice(-20);

// Build messages array for LLM
const messages = [
  {
    role: 'system',
    content: `You are a helpful AI assistant with access to tools. Today is ${new Date().toDateString()}. You can search the web, run calculations, look up weather, and query databases. Always think step-by-step and explain which tools you are using and why. Session: ${sessionId}`
  },
  ...history,
  { role: 'user', content: userMessage }
];

return [{ json: { messages, history, userMessage, sessionId, userId } }];

