// Detect if the model wants to call a tool
const response = $input.first().json;
const choice = response.choices[0];
const finishReason = choice.finish_reason;
const toolCalls = choice.message.tool_calls || [];

if (finishReason === 'tool_calls' && toolCalls.length > 0) {
  return [{ json: { needs_tool: true, tool_calls: toolCalls, agent_message: choice.message } }];
} else {
  return [{ json: { needs_tool: false, final_answer: choice.message.content, agent_message: choice.message } }];
}

// Tool dispatcher: execute the appropriate tool based on tool name
const toolCalls = $input.first().json.tool_calls;
const results = [];

for (const tc of toolCalls) {
  const args = JSON.parse(tc.function.arguments);
  let result = '';

  if (tc.function.name === 'calculate') {
    // Safe math evaluation
    try {
      const safeExpr = args.expression.replace(/[^0-9+\-*/().% ]/g, '');
      result = String(eval(safeExpr));
    } catch (e) {
      result = `Error evaluating expression: ${e.message}`;
    }
  } else if (tc.function.name === 'get_weather') {
    // Stubbed – replace with real OpenWeatherMap call in production
    result = JSON.stringify({
      city: args.city,
      country: args.country_code || 'unknown',
      temp_c: 28,
      condition: 'Partly cloudy',
      humidity: '62%',
      note: 'Replace with real OpenWeatherMap API call'
    });
  } else if (tc.function.name === 'web_search') {
    // Stubbed – replace with SerpAPI or Brave Search in production
    result = JSON.stringify({
      query: args.query,
      results: [
        { title: 'Search result 1', snippet: 'Replace with real search API results.', url: 'https://example.com' }
      ],
      note: 'Integrate SerpAPI or Brave Search for live results'
    });
  } else if (tc.function.name === 'query_database') {
    // Stubbed – replace with n8n Postgres/MySQL node in production
    result = JSON.stringify({
      sql: args.sql,
      description: args.description,
      rows: [],
      note: 'Connect a Postgres or MySQL node for real DB queries'
    });
  } else {
    result = `Unknown tool: ${tc.function.name}`;
  }

  results.push({ tool_call_id: tc.id, name: tc.function.name, result });
}

return [{ json: { tool_results: results } }];

