// Collect final answer from either path (direct or after tool use)
const directPath = $('Code – Route: Tool Call or Answer?').item;
const toolPath = $('HTTP – GPT-4o Resume with Tool Results').item;

let finalAnswer = '';
if (toolPath) {
  finalAnswer = toolPath.json.choices[0].message.content;
} else {
  finalAnswer = directPath.json.final_answer;
}

const history = $('Code – Build Message History').item.json.history;
const userMessage = $('Code – Build Message History').item.json.userMessage;
const sessionId = $('Code – Build Message History').item.json.sessionId;

// Append this turn to history
const updatedHistory = [
  ...history,
  { role: 'user', content: userMessage },
  { role: 'assistant', content: finalAnswer }
];

// Keep only last 20 messages
const trimmed = updatedHistory.slice(-20);

return [{ json: { finalAnswer, sessionId, updatedHistory: trimmed, userMessage } }];
